//! Bee-derived conformance test vectors.
//!
//! The JSON files under `conformance/vectors/` are generated by the Go
//! program in `conformance/vectorgen/`, which calls the canonical bee
//! implementation (the sibling `bee` checkout) for every derived value:
//! CAC/BMT addresses, SOC signatures + addresses, feed identifiers, full
//! feed-update chunks, postage stamp digests + signatures, dispersed
//! replica addresses, and the erasure-code parity tables.
//!
//! The tests in `tests/vectors.rs` assert that ant's implementations are
//! bit-exact against those vectors. Regenerate the vectors with:
//!
//! ```sh
//! cd conformance/vectorgen && go run . -out ../vectors
//! ```

pub mod memnode;

pub use memnode::{
    mem_node_public_key_hex, spawn_mem_gateway, MemChunkStore, MemGateway, MemGatewayConfig,
    MEM_NODE_SECRET,
};

use serde::de::DeserializeOwned;
use serde::Deserialize;
use std::path::PathBuf;

/// Directory holding the generated vector JSON files.
#[must_use]
pub fn vectors_dir() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("..")
        .join("..")
        .join("conformance")
        .join("vectors")
}

/// Load and deserialize one vector file by name (e.g. `"soc.json"`).
///
/// # Panics
///
/// Panics if the file is missing or malformed — vectors are checked in,
/// so either is a repo defect, not a runtime condition.
#[must_use]
pub fn load<T: DeserializeOwned>(name: &str) -> T {
    let path = vectors_dir().join(name);
    let blob =
        std::fs::read(&path).unwrap_or_else(|e| panic!("read vector file {}: {e}", path.display()));
    serde_json::from_slice(&blob)
        .unwrap_or_else(|e| panic!("parse vector file {}: {e}", path.display()))
}

/// Decode a hex vector field, panicking with the field name on error.
#[must_use]
pub fn unhex(field: &str, s: &str) -> Vec<u8> {
    hex::decode(s).unwrap_or_else(|e| panic!("bad hex in vector field {field}: {e}"))
}

/// Decode a fixed-size hex vector field.
#[must_use]
pub fn unhex_arr<const N: usize>(field: &str, s: &str) -> [u8; N] {
    let v = unhex(field, s);
    let len = v.len();
    v.try_into()
        .unwrap_or_else(|_| panic!("vector field {field}: expected {N} bytes, got {len}"))
}

