/// One file encoded by bee's real pipeline (`builder.NewPipelineBuilder`)
/// at a `swarm-redundancy-level`. `chunks` holds **every** chunk the
/// pipeline emitted — data, intermediate and parity — and
/// `root_replicas` the dispersed replica SOC wires `replicas.NewPutter`
/// would upload for the root. The file payload is `det("rs/<name>",
/// file_size)` (see `conformance/vectorgen/main.go`).
#[derive(Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct RsFileCase {
    pub name: String,
    pub level: u8,
    pub file_size: usize,
    pub root_hex: String,
    pub chunks: Vec<RsChunkEntry>,
    pub root_replicas: Vec<RsChunkEntry>,
}

#[derive(Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct RsChunkEntry {
    pub address_hex: String,
    pub data_hex: String,
}

#[derive(Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct RedundancyVectors {
    pub levels: Vec<RedundancyLevel>,
}

#[derive(Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct RedundancyLevel {
    pub level: u8,
    pub name: String,
    pub replica_count: u32,
    pub max_shards: u32,
    pub max_enc_shards: u32,
    pub parities: Vec<u32>,
    pub enc_parities: Vec<u32>,
}

#[derive(Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct EncryptionVectors {
    pub chunk_cases: Vec<EncChunkCase>,
    pub tree_cases: Vec<EncTreeCase>,
}

/// One chunk encrypted with bee's `pkg/encryption` primitives under an
/// **injected** key (zero ciphertext padding) — byte-exact targets for
/// ant's `encrypt_chunk_unpadded` / `decrypt_chunk`.
#[derive(Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct EncChunkCase {
    pub name: String,
    pub key_hex: String,
    pub payload_hex: String,
    pub plain_span_hex: String,
    pub enc_span_hex: String,
    pub enc_data_hex: String,
    pub stored_wire_hex: String,
    pub address_hex: String,
}

/// One whole encrypted tree frozen from bee's *real* pipeline
/// (`builder.NewPipelineBuilder` with `encrypt = true`; random keys,
/// fixed once generated). The payload is `det("enc/<name>", file_size)`.
/// Ant's `join_encrypted` must reproduce it from `root_ref_hex`.
#[derive(Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct EncTreeCase {
    pub name: String,
    pub level: u8,
    pub file_size: usize,
    pub root_ref_hex: String,
    pub chunks: Vec<RsChunkEntry>,
    pub root_replicas: Vec<RsChunkEntry>,
}

// --- ACT (access control) vectors -------------------------------------------

/// `act.json`: bee's `pkg/accesscontrol` primitives with injected keys
